class Solution {
    public int countPairs(int[] nums, int low, int high) {
        int res = 0;
        int[] cnt = new int[1 << 14];
        for (int x : nums) {
            for (int i = low; i <= high; i++) {
                res += cnt[x ^ i];
            }
            cnt[x]++;
        }
        return res;
    }
}
